import redis
from datetime import timedelta, datetime

class RedisClient:
    def __init__(self):
        self.redises = []
        
    def connect_to_redis(self, host, port, password=None):
        try:
            r = redis.Redis(host=host, port=port, db=0, socket_timeout=10, socket_connect_timeout=5)
            if password is not None:
                r.auth(password=password)
            self.redises.append(r)
            return r
        except Exception as e:
            print(f"Error connecting to Redis at {host}:{port}: {str(e)}")
    
    def get_redis(self):
        if len(self.redises) == 0:
            raise Exception("No active Redis connections found.")
        
        # For simplicity, use the first connected Redis node
        return self.redises[0]

    def set_token_in_redis(self, token_name, token_value, ttl_hours=24):
        r = self.get_redis()
        expiration_time = datetime.now() + timedelta(hours=int(ttl_hours))
        pipeline = r.pipeline(transaction=False)
        
        pipeline.set(token_name, token_value, px=int(expiration_time.timestamp()))
        return pipeline.execute()[0]

    def get_token_from_redis(self, token_name):
        r = self.get_redis()
        try:
            return r.get(token_name).decode('utf-8')
        except Exception as e:
            print(f"Error getting {token_name} from Redis: {str(e)}")
            return None

# Example usage
if __name__ == "__main__":
    redis_client = RedisClient()
    
    # Connect to multiple Redis nodes (adjust host and port accordingly)
    redis_client.connect_to_redis("redis-host1", 6379, password="redis-password")
    redis_client.connect_to_redis("redis-host2", 6380, password="redis-password")

    token_name = "my-token"
    token_value = "some-secret-value"
    
    # Set and retrieve a token
    print(redis_client.set_token_in_redis(token_name, token_value))
    retrieved_token = redis_client.get_token_from_redis(token_name)
    print(retrieved_token)